/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const N = nums.length;

    // 1. Build Adjacency List
    const adj = Array(N).fill(0).map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let validSubsetsCount = 0;
    const totalSubsets = 1 << N;

    // 2. Iterate through all non-empty subsets (masks M from 1 to 2^N - 1)
    for (let M = 1; M < totalSubsets; M++) {

        // --- Step 1: Check Sum Parity ---
        let currentSum = 0;
        let nodesInS = [];
        for (let i = 0; i < N; i++) {
            if ((M >> i) & 1) {
                currentSum += nums[i];
                nodesInS.push(i);
            }
        }

        // Condition 2: Sum must be even
        if (currentSum % 2 !== 0) {
            continue;
        }

        // --- Step 2: Check Connectivity ---

        // Since M is non-empty, nodesInS is not empty. Pick the first node as start.
        const startNode = nodesInS[0];
        const targetSize = nodesInS.length;

        // BFS for connectivity check
        const queue = [startNode];
        const visited = new Set([startNode]);
        let reachableCount = 0;

        while (queue.length > 0) {
            const u = queue.shift();
            reachableCount++;

            for (const v of adj[u]) {
                // Check if v is in S (i.e., v-th bit is set in M)
                const vInS = (M >> v) & 1;

                // Check if v hasn't been visited
                if (vInS && !visited.has(v)) {
                    visited.add(v);
                    queue.push(v);
                }
            }
        }

        // Condition 1: Induced subgraph must be connected
        if (reachableCount === targetSize) {
            validSubsetsCount++;
        }
    }

    return validSubsetsCount;
}

